import type { AmountAllocationAttributes } from "@workspace/api-client/public";
import type { AmountAllocation } from "@workspace/api-client/types";
import { describe, expect, it } from "vitest";
import { reallocateAmount } from "./reallocate-amount";

const createMockAmountAllocation = (
  amount: number,
  id: string,
): AmountAllocation => ({
  amount,
  createdAt: new Date().toISOString(),
  id,
  updatedAt: new Date().toISOString(),
});

const createMockAmountAllocationAttributes = (
  amount: number,
  id: string,
): AmountAllocationAttributes => ({
  amount,
  id,
});

describe("reallocateAmount", () => {
  it("should maintain distribution percentages when reallocating", () => {
    const currentAllocations = [
      createMockAmountAllocation(6000, "fund1"), // 60%
      createMockAmountAllocation(3000, "fund2"), // 30%
      createMockAmountAllocation(1000, "fund3"), // 10%
    ];

    const newTotalAmount = 5000; // 50% of original

    const result = reallocateAmount(newTotalAmount, currentAllocations);

    expect(result).toEqual([
      createMockAmountAllocationAttributes(3000, "fund1"), // 60% of 5000
      createMockAmountAllocationAttributes(1500, "fund2"), // 30% of 5000
      createMockAmountAllocationAttributes(500, "fund3"), // 10% of 5000
    ]);

    // Verify total matches
    const total = result.reduce(
      (sum, allocation) => sum + allocation.amount,
      0,
    );
    expect(total).toBe(newTotalAmount);
  });

  it("should handle rounding errors by distributing remainder", () => {
    const currentAllocations = [
      createMockAmountAllocation(1000, "fund1"), // 33.33%
      createMockAmountAllocation(1000, "fund2"), // 33.33%
      createMockAmountAllocation(1000, "fund3"), // 33.33%
    ];

    const newTotalAmount = 100; // This will cause rounding issues

    const result = reallocateAmount(newTotalAmount, currentAllocations);

    // Verify total matches exactly
    const total = result.reduce(
      (sum, allocation) => sum + allocation.amount,
      0,
    );
    expect(total).toBe(newTotalAmount);

    // Verify all allocations are reasonable (not negative)
    result.forEach((allocation) => {
      expect(allocation.amount).toBeGreaterThanOrEqual(0);
    });
  });

  it("should handle zero current total by distributing equally", () => {
    const currentAllocations = [
      createMockAmountAllocation(0, "fund1"),
      createMockAmountAllocation(0, "fund2"),
      createMockAmountAllocation(0, "fund3"),
    ];

    const newTotalAmount = 1000;

    const result = reallocateAmount(newTotalAmount, currentAllocations);

    // Should distribute equally with remainder handled
    const total = result.reduce(
      (sum, allocation) => sum + allocation.amount,
      0,
    );
    expect(total).toBe(newTotalAmount);

    // All allocations should be close to equal
    const expectedPerAllocation = Math.floor(newTotalAmount / 3);
    result.forEach((allocation) => {
      expect(allocation.amount).toBeGreaterThanOrEqual(expectedPerAllocation);
      expect(allocation.amount).toBeLessThanOrEqual(expectedPerAllocation + 1);
    });
  });

  it("should return empty array for empty allocations", () => {
    const result = reallocateAmount(1000, []);
    expect(result).toEqual([]);
  });

  it("should handle single allocation", () => {
    const currentAllocations = [createMockAmountAllocation(5000, "fund1")];
    const newTotalAmount = 3000;

    const result = reallocateAmount(newTotalAmount, currentAllocations);

    expect(result).toEqual([
      createMockAmountAllocationAttributes(3000, "fund1"),
    ]);
  });

  it("should handle very small amounts", () => {
    const currentAllocations = [
      createMockAmountAllocation(1, "fund1"),
      createMockAmountAllocation(2, "fund2"),
      createMockAmountAllocation(3, "fund3"),
    ];

    const newTotalAmount = 5;

    const result = reallocateAmount(newTotalAmount, currentAllocations);

    const total = result.reduce(
      (sum, allocation) => sum + allocation.amount,
      0,
    );
    expect(total).toBe(newTotalAmount);
  });

  it("should preserve allocation order", () => {
    const currentAllocations = [
      createMockAmountAllocation(1000, "fund1"),
      createMockAmountAllocation(2000, "fund2"),
      createMockAmountAllocation(3000, "fund3"),
    ];

    const newTotalAmount = 6000;

    const result = reallocateAmount(newTotalAmount, currentAllocations);

    // Should maintain the same order
    expect(result[0].id).toBe("fund1");
    expect(result[1].id).toBe("fund2");
    expect(result[2].id).toBe("fund3");
  });
});

