import { render, screen } from "@workspace/test-utils";
import { Button } from "@workspace/ui";
import { PageHeader } from "./page-header";

describe("PageHeader", () => {
  it("should render without errors", () => {
    render(<PageHeader />);
    expect(screen.getByRole("banner")).toBeVisible();
  });

  it("should render children content", () => {
    render(
      <PageHeader>
        <div data-testid="test-content">Test Content</div>
      </PageHeader>,
    );
    expect(screen.getByTestId("test-content")).toBeVisible();
  });

  it("should render actions when provided", () => {
    render(
      <PageHeader
        actions={<Button data-testid="test-action">Test Action</Button>}
      />,
    );
    expect(screen.getByTestId("test-action")).toBeVisible();
  });

  it("should apply custom className to the container", () => {
    render(<PageHeader className="test-class" />);
    const container = screen.getByRole("banner");
    expect(container).toHaveClass("test-class");
  });

  it("should apply custom contentClassName to the content area", () => {
    render(<PageHeader contentClassName="test-content-class" />);
    const contentArea = screen.getByRole("banner").firstChild as HTMLElement;
    expect(contentArea).toHaveClass("test-content-class");
  });

  it("should apply custom actionsClassName to the actions area", () => {
    render(
      <PageHeader
        actions={<Button>Test Action</Button>}
        actionsClassName="test-actions-class"
      />,
    );
    const actionsArea = screen.getByRole("banner").lastChild as HTMLElement;
    expect(actionsArea).toHaveClass("test-actions-class");
  });
});

